#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
const int N=2e5+5;
long long exgcd(long long a,long long b,long long &x,long long &y)
	{long long res=a,tmp;b?(res=exgcd(b,a%b,x,y),tmp=x,x=y,y=tmp-a/b*y):(x=1,y=0);return res;}
inline long long Mul(long long a,long long b,long long Mod)
	{long long res=0;while(b){if(b&1)res=(res+a)%Mod;a=(a<<1)%Mod;b=b>>1;}return res;}
inline long long Read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
long long m[N],r[N];
int main()
{
	int n=read();rep(1,n,i)m[i]=Read(),r[i]=Read();
	long long M=m[1],ans=r[1],x,y;rep(2,n,i)
	{
		long long GCD=exgcd(M,m[i],x,y),lcm=m[i]/GCD,c=(r[i]-ans%m[i]+m[i])%m[i];
		x=Mul(x,c/GCD,lcm);ans+=x*M;M*=lcm;ans=(ans%M+M)%M;//
	}
	printf("%lld\n",ans);
}
